// Verifica se a coleta retornou produtos
const res = $input.first().json;

if (!res.ok) {
  throw new Error(`Coleta falhou: ${res.erro || 'Erro desconhecido'}`);
}

const produtos = res.produtos || [];

if (!produtos.length) {
  console.log('Nenhum produto novo nesta execução.');
  return [];
}

console.log(`Coleta OK: ${produtos.length} produtos | Stats:`, JSON.stringify(res.stats));

// Explode em itens individuais para o Google Sheets
return produtos.map(p => ({ json: p }));

// Formata campos para a planilha
const p = $input.item.json;

const formatBRL = v => v != null ? `R$ ${Number(v).toFixed(2).replace('.', ',')}` : '';

return {
  json: {
    ID:              p.ID || '',
    PLATAFORMA:      'Mercado Livre',
    ORIGEM:          p.ORIGEM || '',
    PRODUTO:         p.PRODUTO || '',
    PRECO_DE:        p.PRECO_DE || '',
    PRECO_POR:       p.PRECO_POR || '',
    PRECO_DE_TEXTO:  formatBRL(p.PRECO_DE),
    PRECO_POR_TEXTO: formatBRL(p.PRECO_POR),
    DESCONTO_PCT:    p.DESCONTO_PCT || '',
    COMISSAO_PCT:    p.COMISSAO_PCT || '',
    GANHO_EXTRA:     p.GANHO_EXTRA ? 'SIM' : 'NAO',
    DESTAQUE:        p.DESTAQUE || '',
    LINK_ORIGINAL:   p.LINK_ORIGINAL || '',
    LINK_AFILIADO:   p.LINK_AFILIADO || '',
    LINK_IMAGEM:     p.LINK_IMAGEM || '',
    DATA_COLETA:     p.DATA_COLETA || new Date().toISOString(),
    STATUS:          'NOVO',
  }
};

const items = $input.all();
console.log(`✅ Gravados ${items.length} produtos na planilha ML_BRUTOS`);
return [{ json: { ok: true, gravados: items.length, timestamp: new Date().toISOString() } }];
